create table if not exists attribute_count (
    document_version_id bigint primary key references document_version(id) on delete cascade,
    attribute_definitions bigint not null,
    counted_at timestamptz not null default now()
);

create index if not exists idx_attribute_count_counted_at on attribute_count(counted_at);

